/**
 * Agent discovery — reads ~/.pi/agents/*.md and .pi/agents/*.md
 * Adapted from pi's official subagent example
 */

import * as fs from "node:fs";
import * as path from "node:path";
import * as os from "node:os";

export interface AgentConfig {
	name: string;
	description: string;
	tools?: string[];
	model?: string;
	systemPrompt: string;
	source: "user" | "project";
	filePath: string;
}

function parseFrontmatter(content: string): { frontmatter: Record<string, string>; body: string } {
	const lines = content.split("\n");
	if (lines[0]?.trim() !== "---") {
		return { frontmatter: {}, body: content };
	}

	const endIdx = lines.indexOf("---", 1);
	if (endIdx === -1) {
		return { frontmatter: {}, body: content };
	}

	const frontmatter: Record<string, string> = {};
	for (const line of lines.slice(1, endIdx)) {
		const colonIdx = line.indexOf(":");
		if (colonIdx === -1) continue;
		const key = line.slice(0, colonIdx).trim();
		const value = line.slice(colonIdx + 1).trim();
		if (key) frontmatter[key] = value;
	}

	const body = lines.slice(endIdx + 1).join("\n").trim();
	return { frontmatter, body };
}

function loadAgentsFromDir(dir: string, source: "user" | "project"): AgentConfig[] {
	const agents: AgentConfig[] = [];
	if (!fs.existsSync(dir)) return agents;

	function walkDir(currentDir: string) {
		let entries: fs.Dirent[];
		try {
			entries = fs.readdirSync(currentDir, { withFileTypes: true });
		} catch {
			return;
		}

		for (const entry of entries) {
			const fullPath = path.join(currentDir, entry.name);
			if (entry.isDirectory()) {
				walkDir(fullPath);
				continue;
			}
			if (!entry.name.endsWith(".md")) continue;

			let content: string;
			try {
				content = fs.readFileSync(fullPath, "utf-8");
			} catch {
				continue;
			}

			const { frontmatter, body } = parseFrontmatter(content);
			if (!frontmatter.name || !frontmatter.description) continue;

			const tools = frontmatter.tools
				?.split(",")
				.map((t: string) => t.trim())
				.filter(Boolean);

			agents.push({
				name: frontmatter.name,
				description: frontmatter.description,
				tools: tools && tools.length > 0 ? tools : undefined,
				model: frontmatter.model,
				systemPrompt: body,
				source,
				filePath: fullPath,
			});
		}
	}

	walkDir(dir);
	return agents;
}

function findProjectAgentsDir(cwd: string): string | null {
	let currentDir = cwd;
	while (true) {
		const candidate = path.join(currentDir, ".pi", "agents");
		try {
			if (fs.statSync(candidate).isDirectory()) return candidate;
		} catch {}
		const parent = path.dirname(currentDir);
		if (parent === currentDir) return null;
		currentDir = parent;
	}
}

export function discoverAgents(cwd: string): AgentConfig[] {
	const userDir = path.join(os.homedir(), ".pi", "agents");
	const projectDir = findProjectAgentsDir(cwd);

	const agentMap = new Map<string, AgentConfig>();

	for (const agent of loadAgentsFromDir(userDir, "user")) {
		agentMap.set(agent.name, agent);
	}
	if (projectDir) {
		for (const agent of loadAgentsFromDir(projectDir, "project")) {
			agentMap.set(agent.name, agent);
		}
	}

	return Array.from(agentMap.values());
}

/**
 * Handoff file builder and result reader
 *
 * HANDOFF format: what Herald sends to each sub-agent
 * DIGEST format:  what sub-agents write back (structured, lightweight)
 */

import * as fs from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import * as crypto from "node:crypto";

export function generateId(): string {
	return crypto.randomBytes(4).toString("hex");
}

/** Write the handoff file the agent will receive as its task prompt */
export function buildHandoffFile(
	id: string,
	from: string,
	to: string,
	context: string,
	task: string,
): string {
	const filePath = path.join(os.tmpdir(), `pi-handoff-${id}.md`);

	const resultPath = path.join(os.tmpdir(), `pi-result-${id}.md`);

	const content = [
		`HANDOFF`,
		`from: ${from}  to: ${to}  id: ${id}`,
		`---`,
		context.trim() ? `## Context\n${context.trim()}` : "",
		`## Task\n${task.trim()}`,
		`## Output`,
		`Save your result to: ${resultPath}`,
		`Use the DIGEST format:`,
		``,
		"```",
		`DIGEST`,
		`agent: ${to}`,
		`status: done | error | blocked`,
		`---`,
		`## Summary`,
		`[max 2 sentences]`,
		``,
		`## Findings`,
		`- finding 1`,
		``,
		`## Files`,
		`- path/file.ts:42 — reason`,
		``,
		`## Next`,
		`[optional: what the orchestrator needs to do with this]`,
		"```",
	]
		.filter((line) => line !== null)
		.join("\n");

	fs.writeFileSync(filePath, content, { encoding: "utf-8", mode: 0o600 });
	return filePath;
}

/** Write the agent's system prompt to a temp file for --append-system-prompt */
export function buildSystemPromptFile(id: string, agentName: string, systemPrompt: string): string {
	const filePath = path.join(os.tmpdir(), `pi-sysprompt-${id}-${agentName}.md`);
	fs.writeFileSync(filePath, systemPrompt, { encoding: "utf-8", mode: 0o600 });
	return filePath;
}

/** Write the shell script that runs pi in the tmux pane */
export function buildRunScript(
	id: string,
	model: string | undefined,
	syspromptPath: string,
	tools: string[] | undefined,
	handoffPath: string,
	resultPath: string,
	donePath: string,
): string {
	const scriptPath = path.join(os.tmpdir(), `pi-run-${id}.sh`);

	const modelFlag = model ? `--model "${model}"` : "";
	const toolsFlag = tools && tools.length > 0 ? `--tools "${tools.join(",")}"` : "--no-tools";

	const script = `#!/bin/bash
# pi tmux-delegate run script — id: ${id}
RESULT="${resultPath}"
DONE="${donePath}"
HANDOFF="${handoffPath}"

pi --no-session ${modelFlag} \\
   --append-system-prompt "${syspromptPath}" \\
   ${toolsFlag} \\
   -p "$(cat "$HANDOFF")" \\
   2>&1 | tee "$RESULT"

EXIT_CODE=$\{PIPESTATUS[0]}
echo "$EXIT_CODE" > "$DONE"

# Keep pane briefly visible — will be killed by orchestrator after result is read
sleep 3
`;

	fs.writeFileSync(scriptPath, script, { encoding: "utf-8", mode: 0o755 });
	return scriptPath;
}

const POLL_INTERVAL_MS = 500;

/** Poll until the done sentinel exists or timeout/abort */
export async function waitForResult(
	donePath: string,
	timeoutMs = 300_000,
	signal?: AbortSignal,
): Promise<void> {
	const deadline = Date.now() + timeoutMs;

	return new Promise((resolve, reject) => {
		const check = () => {
			if (signal?.aborted) {
				reject(new Error("Delegate aborted by user"));
				return;
			}
			if (Date.now() > deadline) {
				reject(new Error(`Agent timed out after ${timeoutMs / 1000}s`));
				return;
			}
			if (fs.existsSync(donePath)) {
				resolve();
				return;
			}
			setTimeout(check, POLL_INTERVAL_MS);
		};
		check();
	});
}

/** Read the result file written by the agent */
export function readResult(resultPath: string): string {
	try {
		return fs.readFileSync(resultPath, "utf-8").trim();
	} catch {
		return "(no output — agent may have crashed)";
	}
}

/** Remove temp files */
export function cleanup(paths: string[]): void {
	for (const p of paths) {
		try {
			fs.unlinkSync(p);
		} catch {}
	}
}

/**
 * Tmux pane management with adaptive layout
 *
 * Layout logic (based on active pane count when spawning):
 *   0 active → split-window -h -p 30        [main | pane1]
 *   1 active → split pane1 -v -p 50         [main | pane1 ]
 *                                            [     | pane2 ]
 *   2+ active → split pane1 -h -p 40        [main | pane1 | pane3]
 *                                            [     | pane2 |      ]
 */

import { execSync, spawn } from "node:child_process";
import * as os from "node:os";

export interface PaneInfo {
	id: string;
	agentName: string;
	runScriptPath: string;
	pid?: number;
}

export class TmuxLayout {
	private activePanes: PaneInfo[] = [];

	isInTmux(): boolean {
		return Boolean(process.env.TMUX);
	}

	/** Spawn agent in a tmux pane (or background process if not in tmux) */
	createPane(agentName: string, runScriptPath: string): string {
		if (!this.isInTmux()) {
			return this.spawnBackground(agentName, runScriptPath);
		}
		return this.spawnTmuxPane(agentName, runScriptPath);
	}

	/** Remove pane from tracking and kill it */
	removePane(paneId: string): void {
		this.activePanes = this.activePanes.filter((p) => p.id !== paneId);

		if (paneId.startsWith("bg-")) {
			// Background process — kill by pid if we have it
			const info = this.activePanes.find((p) => p.id === paneId);
			if (info?.pid) {
				try {
					process.kill(info.pid, "SIGTERM");
				} catch {}
			}
			return;
		}

		// Kill tmux pane (may already be gone if pane auto-closed)
		try {
			execSync(`tmux kill-pane -t "${paneId}" 2>/dev/null`, { stdio: "ignore" });
		} catch {}
	}

	private spawnTmuxPane(agentName: string, runScriptPath: string): string {
		const count = this.activePanes.length;
		const cmd = `bash '${runScriptPath}'`;
		let paneId: string;

		try {
			if (count === 0) {
				// First pane: vertical split on the right, 30% width
				paneId = execSync(
					`tmux split-window -h -p 30 -d -P -F "#{pane_id}" "${cmd}"`,
				)
					.toString()
					.trim();
			} else if (count === 1) {
				// Second pane: horizontal split below first right pane
				const firstPane = this.activePanes[0].id;
				paneId = execSync(
					`tmux split-window -v -p 50 -d -t "${firstPane}" -P -F "#{pane_id}" "${cmd}"`,
				)
					.toString()
					.trim();
			} else {
				// Third+ pane: new vertical column to the right of existing column
				const firstPane = this.activePanes[0].id;
				paneId = execSync(
					`tmux split-window -h -p 40 -d -t "${firstPane}" -P -F "#{pane_id}" "${cmd}"`,
				)
					.toString()
					.trim();
			}
		} catch (err) {
			// Tmux command failed — fall back to background
			console.error(`[tmux-delegate] Failed to create pane: ${err}`);
			return this.spawnBackground(agentName, runScriptPath);
		}

		this.activePanes.push({ id: paneId, agentName, runScriptPath });
		return paneId;
	}

	private spawnBackground(agentName: string, runScriptPath: string): string {
		const id = `bg-${agentName}-${Date.now()}`;
		const proc = spawn("bash", [runScriptPath], {
			detached: true,
			stdio: "ignore",
			cwd: os.homedir(),
		});
		proc.unref();

		const info: PaneInfo = {
			id,
			agentName,
			runScriptPath,
			pid: proc.pid,
		};
		this.activePanes.push(info);
		return id;
	}

	get count(): number {
		return this.activePanes.length;
	}

	getActiveAgents(): string[] {
		return this.activePanes.map((p) => p.agentName);
	}
}

/**
 * tmux-delegate — Pi extension
 *
 * Registers a `delegate` tool that Herald (the orchestrator) uses to
 * spawn specialized agents in isolated pi processes running in tmux panes.
 *
 * Layout adapts based on number of active panes:
 *   1 agent  → vertical split, 30% right
 *   2 agents → + horizontal split below the first
 *   3+ agents → + new vertical column to the right
 *
 * Panes close automatically after the agent finishes (3s grace period).
 */

import * as fs from "node:fs";
import * as path from "node:path";
import * as os from "node:os";
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { Type } from "typebox";
import { discoverAgents, type AgentConfig } from "./agents.js";
import {
	generateId,
	buildHandoffFile,
	buildSystemPromptFile,
	buildRunScript,
	waitForResult,
	readResult,
	cleanup,
} from "./handoff.js";
import { TmuxLayout } from "./tmux.js";

// ─── Shared layout state (persists across delegate calls) ─────────────────────
const layout = new TmuxLayout();

// ─── Single task input type ────────────────────────────────────────────────────
const TaskSchema = Type.Object({
	agent: Type.String({ description: "Agent name: scout, sage, forge, arbiter, ward, explore, review, verify" }),
	task: Type.String({ description: "Task description for the agent" }),
	context: Type.Optional(Type.String({ description: "Minimal context the agent needs (no full history)" })),
});

// ─── Extension entry point ─────────────────────────────────────────────────────
export default function (pi: ExtensionAPI) {
	pi.registerTool({
		name: "delegate",
		label: "Delegate to Agent",
		description:
			"Delegate a task to a specialized agent running in an isolated pi process with its own context window. " +
			"Spawns a tmux pane so you can see what the agent is doing. " +
			"For parallel tasks, pass a `tasks` array — but ALWAYS present the plan to the user first and wait for confirmation.",

		promptSnippet: "Spawn scout, sage, forge, arbiter, ward, explore, review, or verify in isolated context",

		promptGuidelines: [
			"Use delegate whenever you need to run a specialized agent (scout, sage, forge, arbiter, ward, explore, review, verify).",
			"For parallel execution, pass delegate.tasks as an array. Always show the user what will run in parallel and wait for explicit confirmation before calling.",
			"delegate mode 'await' (default) blocks until the agent finishes and returns the result. Use 'fire' only for background tasks where you don't need the output.",
			"Always pass only minimal context — never dump the full conversation history into the context field.",
		],

		parameters: Type.Object({
			// ── Single-agent mode ────────────────────────────────────────────
			agent: Type.Optional(
				Type.String({
					description: "Agent to spawn (single mode). One of: scout, sage, forge, arbiter, ward, explore, review, verify",
				}),
			),
			task: Type.Optional(
				Type.String({ description: "Task for the agent (single mode)" }),
			),
			context: Type.Optional(
				Type.String({ description: "Minimal context the agent needs — no history" }),
			),
			mode: Type.Optional(
				Type.String({ description: "'await' (default, wait for result) or 'fire' (background, no result)" }),
			),
			// ── Parallel mode ────────────────────────────────────────────────
			tasks: Type.Optional(
				Type.Array(TaskSchema, {
					description: "Array of tasks to run in parallel. Present plan to user before calling.",
				}),
			),
		}),

		async execute(toolCallId, params, signal, onUpdate, ctx) {
			const cwd = ctx.cwd;
			const agents = discoverAgents(cwd);

			// ── Build task list ──────────────────────────────────────────────
			const taskList: Array<{ agent: string; task: string; context: string }> =
				params.tasks && params.tasks.length > 0
					? params.tasks.map((t) => ({
							agent: t.agent,
							task: t.task,
							context: t.context ?? "",
						}))
					: params.agent && params.task
						? [{ agent: params.agent, task: params.task, context: params.context ?? "" }]
						: [];

			if (taskList.length === 0) {
				return {
					content: [{ type: "text", text: "Error: specify `agent` + `task` or a `tasks` array." }],
				};
			}

			const mode = params.mode === "fire" ? "fire" : "await";
			const isParallel = taskList.length > 1;

			// ── Validate all agents exist before spawning any ────────────────
			const resolved: Array<{ config: AgentConfig; task: string; context: string }> = [];
			for (const item of taskList) {
				const config = agents.find((a) => a.name === item.agent);
				if (!config) {
					return {
						content: [
							{
								type: "text",
								text: `Error: agent "${item.agent}" not found. Available: ${agents.map((a) => a.name).join(", ")}`,
							},
						],
					};
				}
				resolved.push({ config, task: item.task, context: item.context });
			}

			// ── Notify ───────────────────────────────────────────────────────
			const names = resolved.map((r) => r.config.name).join(", ");
			onUpdate?.({
				content: [
					{
						type: "text",
						text: `[tmux-delegate] Spawning: ${names}${isParallel ? " (parallel)" : ""}`,
					},
				],
			});

			// ── Spawn jobs ───────────────────────────────────────────────────
			const jobs = resolved.map(({ config, task, context }) =>
				runAgent(config, task, context, cwd, signal, onUpdate),
			);

			if (mode === "fire") {
				// Fire and forget — don't await
				Promise.all(jobs).catch(() => {});
				return {
					content: [
						{
							type: "text",
							text: `Spawned ${taskList.length} agent(s) in background (fire mode). No result returned.`,
						},
					],
				};
			}

			// ── Await all ────────────────────────────────────────────────────
			let results: string[];
			try {
				results = await Promise.all(jobs);
			} catch (err: any) {
				return {
					content: [{ type: "text", text: `Delegate error: ${err?.message ?? err}` }],
					isError: true,
				};
			}

			// ── Format output ────────────────────────────────────────────────
			const output =
				results.length === 1
					? results[0]
					: results
							.map((r, i) => `### ${resolved[i].config.name}\n\n${r}`)
							.join("\n\n---\n\n");

			return { content: [{ type: "text", text: output }] };
		},
	});
}

// ─── Core: run one agent ───────────────────────────────────────────────────────
async function runAgent(
	agent: AgentConfig,
	task: string,
	context: string,
	cwd: string,
	signal: AbortSignal | undefined,
	onUpdate?: (partial: any) => void,
): Promise<string> {
	const id = generateId();
	const resultPath = path.join(os.tmpdir(), `pi-result-${id}.md`);
	const donePath = path.join(os.tmpdir(), `pi-result-${id}.done`);

	const handoffPath = buildHandoffFile(id, "herald", agent.name, context, task);
	const syspromptPath = buildSystemPromptFile(id, agent.name, agent.systemPrompt);
	const runScriptPath = buildRunScript(
		id,
		agent.model,
		syspromptPath,
		agent.tools,
		handoffPath,
		resultPath,
		donePath,
	);

	onUpdate?.({
		content: [{ type: "text", text: `  → [${agent.name}] spawning pane (model: ${agent.model ?? "default"})` }],
	});

	const paneId = layout.createPane(agent.name, runScriptPath);

	try {
		// Wait for agent to finish (5 min timeout per agent)
		await waitForResult(donePath, 5 * 60 * 1000, signal);

		const result = readResult(resultPath);

		onUpdate?.({
			content: [{ type: "text", text: `  ✓ [${agent.name}] done` }],
		});

		return result;
	} catch (err) {
		const partial = readResult(resultPath);
		return partial
			? `(incomplete — ${(err as Error).message})\n\n${partial}`
			: `(error — ${(err as Error).message})`;
	} finally {
		// Small delay so user can see the output before pane closes
		await sleep(1000);
		layout.removePane(paneId);
		cleanup([handoffPath, syspromptPath, runScriptPath, donePath]);
		// Keep resultPath — Herald may want to re-read it
		// It gets cleaned up on next delegate call or session end
	}
}

// ─── Helpers ──────────────────────────────────────────────────────────────────
function sleep(ms: number): Promise<void> {
	return new Promise((resolve) => setTimeout(resolve, ms));
}

